const WebSocket = require('ws');

const PORT = 8080;
const wss = new WebSocket.Server({ port: PORT });

wss.on('connection', (ws) => {
  console.log('A new client connected');

  ws.on('message', (message) => {
    console.log(`Received: ${message}`);

    // Broadcast the message to all clients
    wss.clients.forEach(client => {
      if (client !== ws && client.readyState === WebSocket.OPEN) {
        client.send(message);
      }
    });
  });

  ws.on('close', () => {
    console.log('Client disconnected');
  });
});

console.log(`WebSocket server is running on ws://localhost:${PORT}`);

function first() {
  second();
}

function second() {
  third();
}

function third() {
  // This will throw an error
  throw new Error('Oops! Something went wrong.');
}

try {
  first();
} catch (error) {
  console.log(error.stack);
}

function formatStack(error) {
  if (!error.stack) return '';
  const lines = error.stack.split('\n').slice(1);  // remove the error message
  return lines.map(line => {
    // Example stack line: ' at functionName (file:line:column)'
    const match = line.match(/at\s+(\S+)\s+\((.*):(\d+):(\d+)\)/);
    if (match) {
      const [, functionName, file, lineNum, colNum] = match;
      return `${functionName} at ${file}:${lineNum}:${colNum}`;
    }
    return line.trim();
  }).join('\n');
}

try {
  first();
} catch (error) {
  console.log('Custom formatted stack trace:\n' + formatStack(error));
}

class CustomError extends Error {
  constructor(message) {
    super(message);
    this.name = 'CustomError';
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, CustomError);
    }
  }

  getFormattedStack() {
    return this.stack.split('\n')
      .slice(1)
      .map(line => `--> ${line.trim()}`)
      .join('\n');
  }
}

try {
  throw new CustomError('Something went terribly wrong');
} catch (err) {
  console.log(err.name + ': ' + err.message);
  console.log(err.getFormattedStack());
}

interface Category {
  id: string;
  name: string;
  description?: string; // optional property
}

interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: Category; // relation between product and category
  tags?: string[]; // optional array of tags
  stock: number;
  createdAt: Date;
}

interface User {
  id: string;
  name: string;
  email: string;
  address?: string;
  phone?: string;
  createdAt: Date;
}

interface OrderItem {
  product: Product;
  quantity: number;
}

interface Order {
  id: string;
  user: User;
  items: OrderItem[];
  totalAmount: number;
  createdAt: Date;
  status: 'pending' | 'shipped' | 'delivered' | 'cancelled';
}

const electronicsCategory: Category = {
  id: 'cat1',
  name: 'Electronics',
  description: 'Gadgets and electronic devices'
};

const smartphone: Product = {
  id: 'prod1',
  name: 'Smartphone',
  description: 'Latest model smartphone with high-end specs.',
  price: 799.99,
  category: electronicsCategory,
  tags: ['mobile', 'gadgets', 'technology'],
  stock: 50,
  createdAt: new Date()
};

const userJohn: User = {
  id: 'user1',
  name: 'John Doe',
  email: 'john@example.com',
  createdAt: new Date()
};

const order1: Order = {
  id: 'order1',
  user: userJohn,
  items: [
    { product: smartphone, quantity: 2 }
  ],
